  ('diana-abrams', NULL, 'Diana Abrams', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Diana_Abrams.jpg/:/cr=t:21.8%25,l:0%25,w:100%25,h:56.39%25/rs=w:388,h:291.72932330827064,cg:true', 'MHC-LP', 'NJ', ARRAY['Trauma', 'Empowerment', 'Personal Growth']::text[], ARRAY['English']::text[], ARRAY['Individual', 'Trauma-Informed']::text[], 175, 'Limited', 'Creates a safe space where clients feel seen, heard, and empowered. Practices from a trauma-informed lens with empathy, cultural humility, and collaboration.', true),
