  ('ray-ansarul', NULL, 'Ray Ansarul', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Ray%20Ansarul%20.webp/:/cr=t:12.35%25,l:0%25,w:100%25,h:75.29%25/rs=w:388,h:291.72932330827064,cg:true', 'MHC-I', 'NY', ARRAY['Compassion', 'Collaboration', 'Supportive Care']::text[], ARRAY['English']::text[], ARRAY['Individual', 'Supportive']::text[], 170, 'Waitlist', 'Strives to create a safe, compassionate, and understanding space, with a strong belief that effective therapy grows from a trusting therapeutic relationship and collaborative pacing.', true),
