  ('ranique-bell', NULL, 'Ranique Bell', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Ranique_Bell.webp', 'MHC-LP', 'NJ', ARRAY['Depression', 'Anxiety', 'Trauma']::text[], ARRAY['English']::text[], ARRAY['Individual', 'Family']::text[], 175, 'Limited', 'Brings over ten years of experience helping teenagers, individuals, and families improve relationships, navigate depression and anxiety, heal trauma, and adjust to major life transitions.', true),
  ('vanessa-campos', NULL, 'Vanessa Campos', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Vanessa%20Campos%20PIC%202-1.png', 'MHC-I', 'NY', ARRAY['Autism Support', 'Children', 'Life Transitions']::text[], ARRAY['English', 'Spanish']::text[], ARRAY['Individual', 'Supportive']::text[], 155, 'Available', 'Views therapy as a collaborative process and brings particular interest in supporting children and individuals on the autism spectrum while creating a welcoming space for lasting, positive change.', true),
  ('taylor-carroll', NULL, 'Taylor Carroll', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Taylor%20Carroll%20.webp', 'MHC-LP', 'CT', ARRAY['Anxiety', 'OCD', 'Depression']::text[], ARRAY['English']::text[], ARRAY['Individual', 'CBT']::text[], 190, 'Waitlist', 'Was inspired by personal mental health recovery and now supports children and adults struggling with anxiety, agoraphobia, OCD, depression, and BPD using CBT, DBT, and ERP in a judgment-free environment.', true),
  ('mercedes-carter', NULL, 'Mercedes Carter', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Mercedes%20Carter%20.webp', 'MHC-LP', 'NV', ARRAY['Resilience', 'Depression', 'Anxiety']::text[], ARRAY['English']::text[], ARRAY['Individual', 'CBT']::text[], 130, 'Available', 'Focuses on helping clients regain resilience while navigating adversity, with broad mental health experience and a strong grounding in cognitive behavioral techniques.', true),
  ('kirdania-de-la-cruz', NULL, 'Kirdania De La Cruz', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Kirdania%20De%20La%20Cruz%20.webp', 'MHC-I', 'FL', ARRAY['Anxiety', 'Depression', 'Trauma']::text[], ARRAY['English', 'Spanish']::text[], ARRAY['Individual', 'Mindfulness']::text[], 125, 'Available', 'Brings a compassionate, holistic approach and creates a safe, nonjudgmental space while integrating solution-focused therapy, CBT, and mindfulness for anxiety, depression, trauma, identity concerns, and grief.', true),
  ('grescia-estabridis', NULL, 'Grescia Estabridis', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Grescia%20Estabridis%20.webp', 'MHC-LP', 'CT', ARRAY['Eating Disorders', 'Relationships', 'Life Transitions']::text[], ARRAY['English', 'Spanish']::text[], ARRAY['Individual', 'Couples']::text[], 160, 'Available', 'Provides advocacy, psychoeducation, and evidence-based care for individuals, couples, and families, with clinical experience spanning anxiety, depression, eating disorders, relationship challenges, and major life transitions.', true),
  ('margaret-gonzalez', NULL, 'Margaret Gonzalez', 'https://img1.wsimg.com/isteam/ip/be3b4275-20eb-4372-92a9-bcc3a138027c/Margaret%20Gonzalez.jpeg', 'MHC-I', 'NY', ARRAY['School Counseling', 'Youth Support', 'Culturally Responsive Care']::text[], ARRAY['English', 'Spanish']::text[], ARRAY['Individual', 'Supportive']::text[], 155, 'Available', 'Is a bilingual school counselor in the Bronx and graduate student in mental health counseling, passionate about creating safe, supportive, and culturally responsive spaces where individuals feel heard and empowered.', true)
